<template>

    <div class="background">

        <v-header :button-view="LoginState"></v-header>

        <div>
            <router-view></router-view>
        </div>        

    </div>

</template>

<script>

import { bus } from './main';

import Header from './GeneralComponents/Header.vue'

export default {

    components: {
        'v-header': Header
    },
    data() {
        return {
            LoginState: false
        }
    },
    methods: {
        receiveLoginState() {
            bus.$on('setLoginState', (status) => {
                this.LoginState = status
            })
        }
    },
    created() {
        this.receiveLoginState()
    }

}
</script>

